interface TakeExamContentProps {
  examId: number
  recordId: number
  questions: StartExamResponse["questions"]
  startTime: string
  timeLimitMin: number
  examTitle: string
}

function TakeExamContent({
  examId,
  recordId,
  questions,
  startTime,
  timeLimitMin,
  examTitle,
}: TakeExamContentProps) {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const submitMutation = useSubmitExam()

  const [currentIndex, setCurrentIndex] = useState(0)
  const [answers, setAnswers] = useState<Record<number, string>>({})
  const [showConfirm, setShowConfirm] = useState(false)
  const submittingRef = useRef(false)

  // 拦截浏览器关闭/刷新（beforeunload）
  useEffect(() => {
    const handler = (e: BeforeUnloadEvent) => {
      if (submittingRef.current) return
      e.preventDefault()
    }
    window.addEventListener("beforeunload", handler)
    return () => window.removeEventListener("beforeunload", handler)
  }, [])

  // 拦截路由内跳转（TanStack Router blocker）
  useBlocker({
    shouldBlockFn: () => !submittingRef.current,
    withResolver: true,
  })

  const currentQuestion = questions[currentIndex]

  const handleSelectAnswer = (questionId: number, answer: string) => {
    setAnswers((prev) => ({ ...prev, [questionId]: answer }))
    // 选完自动跳下一题（非最后一题时）
    if (currentIndex < questions.length - 1) {
      setCurrentIndex((i) => i + 1)
    }
  }

  const doSubmit = useCallback(() => {
    // 防止重复提交（超时 + 手动同时触发）
    if (submittingRef.current) return
    submittingRef.current = true

    const answerList = questions.map((q) => ({
      questionId: q.id,
      answer: answers[q.id] ?? "",
    }))

    submitMutation.mutate(
      { examId, recordId, answers: answerList },
      {
        onSuccess: (res) => {
          toast.success(
            t("exam.submitSuccess", { score: res.score }),
          )
          navigate({ to: `/records/${recordId}`, replace: true })
        },
        onError: (err) => {
          toast.error(err.message)
          submittingRef.current = false
        },
      },
    )
  }, [answers, examId, navigate, questions, recordId, submitMutation, t])

  const handleTimeUp = useCallback(() => {
    toast.warning(t("exam.timeUp"))
    doSubmit()
  }, [doSubmit, t])

  const handleConfirmSubmit = () => {
    setShowConfirm(false)
    doSubmit()
  }

  const answeredCount = Object.keys(answers).length

  return (
    <div className="mx-auto max-w-3xl space-y-4">
      {/* 顶部栏：标题 + 倒计时 */}
      <div className="flex items-center justify-between rounded-lg border p-4">
        <h2 className="truncate text-lg font-semibold">{examTitle}</h2>
        {timeLimitMin > 0 && (
          <CountdownTimer
            startTime={startTime}
            timeLimitMin={timeLimitMin}
            onTimeUp={handleTimeUp}
          />
        )}
      </div>

      {/* 题目区域 */}
      <div className="rounded-lg border p-6 space-y-6">
        {/* 题号 */}
        <div className="text-sm text-muted-foreground">
          {t("exam.questionProgress", {
            current: currentIndex + 1,
            total: questions.length,
          })}
        </div>

        {/* 题目内容 */}
        <p className="text-base font-medium whitespace-pre-wrap">
          {currentQuestion.content}
        </p>

        {/* 选项 */}
        <RadioGroup
          value={answers[currentQuestion.id] ?? ""}
          onValueChange={(val) =>
            handleSelectAnswer(currentQuestion.id, val)
          }
          className="space-y-3"
        >
          {OPTION_KEYS.map((key) => {
            const optionField = `option${key}` as keyof typeof currentQuestion
            const optionText = currentQuestion[optionField] as string
            return (
              <div key={key} className="flex items-center gap-3">
                <RadioGroupItem value={key} id={`option-${key}`} />
                <Label
                  htmlFor={`option-${key}`}
                  className="cursor-pointer text-sm"
                >
                  {key}. {optionText}
                </Label>
              </div>
            )
          })}
        </RadioGroup>
      </div>

      {/* 底部导航 */}
      <div className="flex items-center justify-between">
        <div className="flex gap-2">
          <Button
            variant="outline"
            disabled={currentIndex <= 0}
            onClick={() => setCurrentIndex((i) => i - 1)}
          >
            {t("exam.prevQuestion")}
          </Button>
          <Button
            variant="outline"
            disabled={currentIndex >= questions.length - 1}
            onClick={() => setCurrentIndex((i) => i + 1)}
          >
            {t("exam.nextQuestion")}
          </Button>
        </div>
        <Button onClick={() => setShowConfirm(true)}>
          {t("common.submit")} ({answeredCount}/{questions.length})
        </Button>
      </div>

      {/* 题号网格 */}
      <div className="rounded-lg border p-4">
        <div className="flex flex-wrap gap-2">
          {questions.map((q, idx) => {
            const isAnswered = !!answers[q.id]
            const isCurrent = idx === currentIndex
            return (
              <button
                key={q.id}
                type="button"
                className={cn(
                  "flex h-8 w-8 items-center justify-center rounded text-sm font-medium transition-colors",
                  isAnswered && "bg-primary text-primary-foreground",
                  !isAnswered && !isCurrent && "bg-muted text-muted-foreground",
                  isCurrent && "ring-2 ring-primary ring-offset-1",
                )}
                onClick={() => setCurrentIndex(idx)}
              >
                {idx + 1}
              </button>
            )
          })}
        </div>
      </div>

      {/* 提交确认弹窗 */}
      <Dialog open={showConfirm} onOpenChange={setShowConfirm}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("exam.confirmSubmitTitle")}</DialogTitle>
            <DialogDescription>
              {t("exam.confirmSubmitDesc", {
                answered: answeredCount,
                total: questions.length,
              })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowConfirm(false)}>
              {t("common.cancel")}
            </Button>
            <Button
              onClick={handleConfirmSubmit}
              disabled={submitMutation.isPending}
            >
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

