import { useState, useEffect } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useQuery } from "@tanstack/react-query"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Select, SelectTrigger, SelectContent, SelectItem, SelectValue } from "@/components/ui/select"
import { useUpdateExam } from "@/hooks/use-admin-exams"
import { get } from "@/lib/api"
import type { Exam, AccessMode } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/edit")({
  component: EditExamPage,
})

function EditExamPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/edit" })
  const examId = Number(id)
  const updateMutation = useUpdateExam()

  // 获取试卷详情（管理员接口）
  const { data: exam, isLoading } = useQuery<Exam>({
    queryKey: ["admin-exam-detail", examId],
    queryFn: () => get<Exam>(`/api/admin/exams/${examId}`),
    enabled: examId > 0,
  })

  const [title, setTitle] = useState("")
  const [timeLimitMin, setTimeLimitMin] = useState(60)
  const [questionCount, setQuestionCount] = useState(0)
  const [showAnswer, setShowAnswer] = useState(false)
  const [showAnalysis, setShowAnalysis] = useState(false)
  const [maxAttempts, setMaxAttempts] = useState(1)
  const [accessMode, setAccessMode] = useState<AccessMode>("open")

  // 数据加载后填充表单
  useEffect(() => {
    if (!exam) return
    setTitle(exam.title)
    setTimeLimitMin(exam.timeLimitMin)
    setQuestionCount(exam.questionCount)
    setShowAnswer(exam.showAnswer)
    setShowAnalysis(exam.showAnalysis)
    setMaxAttempts(exam.maxAttempts)
    setAccessMode(exam.accessMode)
  }, [exam])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    updateMutation.mutate(
      { id: examId, title, timeLimitMin, questionCount, showAnswer, showAnalysis, maxAttempts, accessMode },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          navigate({ to: "/admin/exams" })
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  return (
    <div className="mx-auto max-w-2xl space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("admin.editExam")}</h1>
        <Button variant="outline" onClick={() => navigate({ to: "/admin/exams" })}>
          {t("common.back")}
        </Button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="space-y-2">
          <Label>{t("admin.examTitle")}</Label>
          <Input value={title} onChange={(e) => setTitle(e.target.value)} required />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.timeLimit")}</Label>
          <Input
            type="number"
            min={1}
            value={timeLimitMin}
            onChange={(e) => setTimeLimitMin(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.questionCount")}</Label>
          <Input
            type="number"
            min={0}
            value={questionCount}
            onChange={(e) => setQuestionCount(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.maxAttempts")}</Label>
          <Input
            type="number"
            min={1}
            value={maxAttempts}
            onChange={(e) => setMaxAttempts(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.accessMode")}</Label>
          <Select value={accessMode} onValueChange={(v) => setAccessMode(v as AccessMode)}>
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="open">{t("admin.accessOpen")}</SelectItem>
              <SelectItem value="whitelist">{t("admin.accessWhitelist")}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnswer")}</Label>
          <Switch checked={showAnswer} onCheckedChange={setShowAnswer} />
        </div>

        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnalysis")}</Label>
          <Switch checked={showAnalysis} onCheckedChange={setShowAnalysis} />
        </div>

        <div className="flex justify-end gap-2 pt-4">
          <Button
            type="button"
            variant="outline"
            onClick={() => navigate({ to: "/admin/exams" })}
          >
            {t("common.cancel")}
          </Button>
          <Button type="submit" disabled={updateMutation.isPending}>
            {t("common.save")}
          </Button>
        </div>
      </form>
    </div>
  )
}

