                  <TableHead className="w-[100px] text-center whitespace-nowrap">{t("admin.respondentCount")}</TableHead>
                  <TableHead className="w-[120px]">{t("admin.createdAt")}</TableHead>
                  <TableHead className="w-[120px]">{t("admin.updatedAt")}</TableHead>
                  <TableHead className="min-w-[260px] text-right">
                    <div className="flex items-center justify-end gap-1">
                      {t("common.actions")}
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-6 w-6"
                        title={showTextActions ? t("common.iconMode") : t("common.textMode")}
                        onClick={toggleTextActions}
                      >
                        {showTextActions ? <ImageIcon className="h-3.5 w-3.5" /> : <Type className="h-3.5 w-3.5" />}
                      </Button>
                    </div>
                  </TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {data.records.map((exam) => (
                  <TableRow key={exam.id}>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        <span
                          className="font-medium cursor-pointer text-blue-600 hover:underline"
                          onClick={() => navigate({ to: `/admin/exams/${exam.id}/detail` })}
                        >
                          {exam.title}
                        </span>
                        {exam.accessMode === "open" && (
                          <Badge variant="outline" className="text-green-600 border-green-300">
                            {t("admin.accessOpen")}
                          </Badge>
                        )}
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge className={STATUS_STYLE[exam.status]}>
                        {t(STATUS_LABEL_KEY[exam.status])}
