import { useTranslation } from "react-i18next"
import { Calendar, Clock, FileQuestion, RotateCcw } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { cn, formatDateTime } from "@/lib/utils"
import type { ExamDetail } from "@/hooks/use-exams"

interface ExamCardProps {
  exam: ExamDetail
  onClick: () => void
}

export function ExamCard({ exam, onClick }: ExamCardProps) {
  const { t } = useTranslation()

  const timeDisplay =
    exam.timeLimitMin > 0
      ? t("exam.timeLimitValue", { min: exam.timeLimitMin })
      : t("exam.noTimeLimit")

  const attemptsDisplay =
    exam.remainingAttempts === null
      ? t("exam.unlimited")
      : t("exam.attemptsValue", { count: exam.remainingAttempts })

  // 状态判断：答题中 > 已完成（剩余0次）> 进行中
  const statusInfo = getStatusInfo(exam, t)

  // 格式化创建时间
  const createdAtDisplay = exam.createdAt
    ? formatDateTime(new Date(exam.createdAt))
    : null

  return (
    <div
      className={cn(
        "cursor-pointer rounded-lg border p-5 transition-colors hover:border-primary/50 hover:shadow-md",
      )}
      onClick={onClick}
    >
      {/* 标题行 */}
      <div className="mb-3 flex items-start justify-between gap-2">
        <h3 className="truncate text-base font-bold">{exam.title}</h3>
        <Badge variant="default" className={cn("shrink-0", statusInfo.className)}>
          {statusInfo.label}
        </Badge>
      </div>

      {/* 信息行 */}
      <div className="space-y-2 text-sm text-muted-foreground">
        <div className="flex items-center gap-1.5">
          <FileQuestion className="h-4 w-4" />
          <span>
            {t("exam.questionCountLabel")}: {exam.questionCount}
            {t("exam.questionUnit")}
          </span>
        </div>
        <div className="flex items-center gap-1.5">
          <Clock className="h-4 w-4" />
          <span>
            {t("exam.timeLimitLabel")}: {timeDisplay}
          </span>
        </div>
        <div className="flex items-center gap-1.5">
          <RotateCcw className="h-4 w-4" />
          <span>
            {t("exam.remainingAttemptsLabel")}: {attemptsDisplay}
          </span>
        </div>
        {createdAtDisplay && (
          <div className="flex items-center gap-1.5">
            <Calendar className="h-4 w-4" />
            <span>
              {t("exam.examTime")}: {createdAtDisplay}
            </span>
          </div>
        )}
      </div>
    </div>
  )
}

function getStatusInfo(
  exam: ExamDetail,
  t: (key: string) => string,
): { label: string; className: string } {
  if (exam.inProgressRecordId != null) {
    // 有进行中的考试记录
    return { label: t("exam.statusInProgress"), className: "bg-orange-500" }
  }
  if (exam.remainingAttempts !== null && exam.remainingAttempts <= 0) {
    // 剩余次数用完
    return { label: t("exam.statusCompleted"), className: "bg-gray-500" }
  }
  // 可以考试
  return { label: t("exam.statusPublished"), className: "bg-green-600" }
}

